from __future__ import annotations

import asyncio
from collections.abc import AsyncIterator
from dataclasses import dataclass, field
from typing import Any


@dataclass(frozen=True)
class IngestPulse:
    event_id: str
    property_id: str
    event_type: str
    status: str
    applied_ops: int
    deferred_ops: int
    commit_sha: str | None

    def to_payload(self) -> dict[str, Any]:
        return {
            "event_id": self.event_id,
            "property_id": self.property_id,
            "event_type": self.event_type,
            "status": self.status,
            "applied_ops": self.applied_ops,
            "deferred_ops": self.deferred_ops,
            "commit_sha": self.commit_sha,
        }


@dataclass
class _Subscriber:
    queue: asyncio.Queue[IngestPulse]
    property_id: str | None = None


class EventBroker:
    """Process-local in-memory pub/sub for ingest pulses.

    A new asyncio.Queue is created per subscriber. Slow consumers do not block
    publishers; queue overflow drops the oldest pulse for that subscriber.
    """

    def __init__(self, *, max_queue: int = 256) -> None:
        self._subs: list[_Subscriber] = []
        self._lock = asyncio.Lock()
        self._max_queue = max_queue

    async def publish(self, pulse: IngestPulse) -> None:
        async with self._lock:
            subs = list(self._subs)
        for sub in subs:
            if sub.property_id is not None and sub.property_id != pulse.property_id:
                continue
            try:
                sub.queue.put_nowait(pulse)
            except asyncio.QueueFull:
                with contextlib_suppress(asyncio.QueueEmpty):
                    sub.queue.get_nowait()
                with contextlib_suppress(asyncio.QueueFull):
                    sub.queue.put_nowait(pulse)

    async def subscribe(
        self,
        *,
        property_id: str | None = None,
    ) -> AsyncIterator[IngestPulse]:
        sub = _Subscriber(queue=asyncio.Queue(maxsize=self._max_queue), property_id=property_id)
        async with self._lock:
            self._subs.append(sub)
        try:
            while True:
                pulse = await sub.queue.get()
                yield pulse
        finally:
            async with self._lock:
                if sub in self._subs:
                    self._subs.remove(sub)


def contextlib_suppress(*excs: type[BaseException]) -> _Suppress:
    return _Suppress(excs)


@dataclass
class _Suppress:
    excs: tuple[type[BaseException], ...] = field(default_factory=tuple)

    def __enter__(self) -> None:
        return None

    def __exit__(self, exc_type, exc, tb) -> bool:  # type: ignore[no-untyped-def]
        return exc_type is not None and issubclass(exc_type, self.excs)


_BROKER: EventBroker | None = None


def get_event_broker() -> EventBroker:
    global _BROKER
    if _BROKER is None:
        _BROKER = EventBroker()
    return _BROKER


def reset_event_broker() -> None:
    """Test helper: drop the singleton so each test starts fresh."""
    global _BROKER
    _BROKER = None

